export default function NewApplicantPage() {
  const router = useRouter();
  const { addToast } = useToast();
  const [currentStep, setCurrentStep] = useState(1);
  const [createApplicant, { isLoading: isSubmitting }] = useCreateApplicantMutation();

  const methods = useForm<FormData>({
    resolver: zodResolver(applicantSchema),
    defaultValues: INITIAL_FORM,
    mode: "onBlur",
  });

  const onSubmit = async (data: FormData) => {
    try {
      await createApplicant(data).unwrap();
      addToast("success", "Applicant Created", `${data.fullName} has been added successfully.`);
      router.push("/applicants");
    } catch (err: any) {
      addToast("error", "Error Creating Applicant", err?.data?.error || "Failed to submit application.");
    }
  };

  const goNext = async () => {
    // Validate current step before proceeding
    const fieldsToValidate: Record<number, (keyof FormData)[]> = {
      1: ["fullName", "dateOfBirth", "gender"],
      2: ["passportNumber", "passportIssueDate", "passportExpiryDate"],
      3: ["mobile", "emergencyContactName", "emergencyPhone"],
      7: ["destinationCountry", "visaType"],
    };

    const fields = fieldsToValidate[currentStep];
    if (fields) {
      const isValid = await methods.trigger(fields);
      if (!isValid) return;
    }

    setCurrentStep((s) => Math.min(s + 1, 8));
  };

  const goPrev = () => setCurrentStep((s) => Math.max(s - 1, 1));

  return (
    <FormProvider {...methods}>
      <form onSubmit={methods.handleSubmit(onSubmit)} className="max-w-4xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex items-center gap-3">
          <button
            type="button"
            onClick={() => router.back()}
            className="p-2 rounded-lg hover:bg-muted transition-colors"
          >
            <ArrowLeft className="w-5 h-5 text-muted-foreground" />
          </button>
          <div>
            <h1 className="text-2xl font-bold tracking-tight">Add New Applicant</h1>
            <p className="text-sm text-muted-foreground mt-0.5">
              Step {currentStep} of {STEPS.length}
            </p>
          </div>
        </div>

        {/* Step Indicator */}
        <div className="flex items-center justify-between mb-8 max-w-3xl mx-auto px-4">
          {STEPS.map((step, idx) => {
            const Icon = step.icon;
            const isActive = step.id === currentStep;
            const isComplete = step.id < currentStep;

            return (
              <React.Fragment key={step.id}>
                <div className="flex flex-col items-center gap-2 group cursor-pointer" onClick={() => isComplete && setCurrentStep(step.id)}>
                  <div className={`w-10 h-10 rounded-full flex items-center justify-center border-2 transition-all duration-300 ${
                    isActive ? "bg-primary border-primary text-primary-foreground shadow-lg scale-110" : 
                    isComplete ? "bg-emerald-500 border-emerald-500 text-white" : 
                    "bg-muted border-border text-muted-foreground"
                  }`}>
                    {isComplete ? <Check className="w-5 h-5" /> : <Icon className="w-5 h-5" />}
                  </div>
                  <span className={`text-[10px] font-bold uppercase tracking-tighter transition-colors ${isActive ? "text-primary" : "text-muted-foreground"}`}>
                    {step.label}
                  </span>
                </div>
                {idx < STEPS.length - 1 && (
                  <div className={`flex-1 h-0.5 mx-2 -mt-6 transition-colors duration-500 ${step.id < currentStep ? "bg-emerald-500" : "bg-border"}`} />
                )}
              </React.Fragment>
            );
          })}
        </div>

        {/* Step Content */}
        <div className="bg-card border border-border rounded-xl p-6">
          {currentStep === 1 && <Step1Personal />}
          {currentStep === 2 && <Step2Passport />}
          {currentStep === 3 && <Step3Contact />}
          {currentStep === 4 && <Step4Education />}
          {currentStep === 5 && <Step5Employment />}
          {currentStep === 6 && <Step6Skills />}
          {currentStep === 7 && <Step7Placement />}
          {currentStep === 8 && <Step8Review setCurrentStep={setCurrentStep} />}
        </div>

        {/* Navigation Buttons */}
        <div className="flex items-center justify-between">
          <button
            type="button"
            onClick={goPrev}
            disabled={currentStep === 1}
            className="flex items-center gap-2 px-4 py-2 rounded-lg bg-card border border-border text-sm font-medium text-foreground hover:bg-muted disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <ArrowLeft className="w-4 h-4" />
            Back
          </button>

          {currentStep < 8 ? (
            <button
              type="button"
              onClick={goNext}
              className="flex items-center gap-2 px-5 py-2 rounded-lg bg-primary text-primary-foreground text-sm font-medium hover:bg-primary/90 transition-colors shadow-sm"
            >
              Next
              <ArrowRight className="w-4 h-4" />
            </button>
          ) : (
            <button
              type="submit"
              disabled={isSubmitting}
              className="flex items-center gap-2 px-5 py-2 rounded-lg bg-emerald-600 text-white text-sm font-medium hover:bg-emerald-700 disabled:opacity-50 transition-colors shadow-sm"
            >
              {isSubmitting ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                <Check className="w-4 h-4" />
              )}
              Create Applicant
            </button>
          )}
        </div>
      </form>
    </FormProvider>
  );
}

"use client";

// eslint-disable-next-line @typescript-eslint/no-unused-vars

import { useState, useMemo, useCallback } from "react";
import { useDebounce } from "@/hooks/useDebounce";
import Link from "next/link";
import {
  Search,
  Filter,
  ChevronDown,
  ChevronUp,
  ChevronsUpDown,
  PlusCircle,
  Download,
  Trash2,
  X,
  Loader2,
} from "lucide-react";
import StatusBadge from "@/components/ui/StatusBadge";
import EmptyState from "@/components/ui/EmptyState";
import ConfirmModal from "@/components/ui/ConfirmModal";
import { SkeletonTable } from "@/components/ui/SkeletonLoader";
import { useGetApplicationsQuery, useDeleteApplicantMutation } from "@/store/api/applicantApi";

// ΓöÇΓöÇ Types ΓöÇΓöÇ
interface ApplicantRow {
  id: string;
  fullName: string;
  caseNumber: string;
  passportNumber: string;
  phone: string;
  type: string;
  destination: string | null;
  jobPosition: string | null;
  status: string;
  assignedAgent: string | null;
  updatedAt: string;
}

const COUNTRIES = ["Japan", "UAE", "Qatar", "Australia", "USA"];
const STATUSES = [
  "PENDING", "DOCUMENTATION_GATHERING", "VERIFICATION", "MEDICAL_PENDING",
  "VISA_SUBMITTED", "PROCESSING", "APPROVED", "REJECTED", "DEPLOYED", "COMPLETED",
];

type SortKey = "fullName" | "status" | "updatedAt";
type SortDir = "asc" | "desc";

export default function ApplicantsPage() {
  const [search, setSearch] = useState("");
  const [filterCountry, setFilterCountry] = useState("");
  const [filterStatus, setFilterStatus] = useState("");
  const [showFilters, setShowFilters] = useState(false);
  const [sortKey, setSortKey] = useState<SortKey>("updatedAt");
  const [sortDir, setSortDir] = useState<SortDir>("desc");
  const [page, setPage] = useState(1);
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const pageSize = 20;

  // Debounce search input ΓÇö prevents API calls on every keystroke
  const debouncedSearch = useDebounce(search, 300);

  const { data: applicantsResponse, isLoading } = useGetApplicationsQuery({ 
    page, 
    limit: pageSize,
    search: debouncedSearch || undefined,
    country: filterCountry || undefined,
    status: filterStatus || undefined,
    sortBy: sortKey,
    sortDir
  });

  const [deleteApplicant, { isLoading: isDeleting }] = useDeleteApplicantMutation();

  const rawApplicants = applicantsResponse?.data || [];

  // Map server response to row shape
  const processed: ApplicantRow[] = useMemo(() => {
    return rawApplicants.map((a) => {
      // The API response includes fields not on ApplicantProfile type
      // (destinationCountry, jobPosition, latestStatus come from the joined application)
      const raw = a as unknown as Record<string, string | null>;
      return {
        id: a.id,
        fullName: a.fullName,
        caseNumber: `HC-${a.id.slice(0, 6)}`,
        passportNumber: a.passportNumber,
        phone: a.phone || "ΓÇö",
        type: a.type,
        destination: raw.destinationCountry ?? null,
        jobPosition: raw.jobPosition ?? null,
        status: raw.latestStatus || "PENDING",
        assignedAgent: null,
        updatedAt: a.updatedAt,
      };
    });
  }, [rawApplicants]);

  const totalPages = applicantsResponse?.meta?.pages || 1;
  const paginated = processed;

  const toggleSort = (key: SortKey) => {
    if (sortKey === key) {
      setSortDir((d) => (d === "asc" ? "desc" : "asc"));
    } else {
      setSortKey(key);
      setSortDir("asc");
    }
    setPage(1);
  };

  const SortIcon = ({ col }: { col: SortKey }) => {
    if (sortKey !== col) return <ChevronsUpDown className="w-3 h-3 text-muted-foreground/40" />;
    return sortDir === "asc" ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />;
  };

  const toggleSelect = (id: string) => {
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const toggleSelectAll = () => {
    if (selected.size === paginated.length) {
      setSelected(new Set());
    } else {
      setSelected(new Set(paginated.map((a) => a.id)));
    }
  };

  const clearFilters = () => {
    setSearch("");
    setFilterCountry("");
    setFilterStatus("");
    setPage(1);
  };

  const hasFilters = !!search || !!filterCountry || !!filterStatus;

  // ΓöÇΓöÇ Bulk Export: Generate CSV from selected rows ΓöÇΓöÇ
  const handleExport = useCallback(() => {
    const selectedRows = paginated.filter((a) => selected.has(a.id));
    if (selectedRows.length === 0) return;

    const headers = ["Full Name", "Case #", "Passport", "Phone", "Type", "Destination", "Position", "Status", "Updated"];
    const csvRows = selectedRows.map((r) => [
      r.fullName,
      r.caseNumber,
      r.passportNumber,
      r.phone,
      r.type,
      r.destination || "",
      r.jobPosition || "",
      r.status.replace(/_/g, " "),
      new Date(r.updatedAt).toLocaleDateString(),
    ]);

    const csvContent = [
      headers.join(","),
      ...csvRows.map((row) => row.map((cell) => `"${cell}"`).join(",")),
    ].join("\n");

    const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `applicants_export_${new Date().toISOString().slice(0, 10)}.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }, [paginated, selected]);

  // ΓöÇΓöÇ Bulk Delete: Confirm then delete all selected ΓöÇΓöÇ
  const handleBulkDelete = useCallback(async () => {
    const ids = Array.from(selected);
    try {
      await Promise.all(ids.map((id) => deleteApplicant(id).unwrap()));
      setSelected(new Set());
      setShowDeleteModal(false);
    } catch {
      // RTK Query will propagate the error via cache invalidation
      setShowDeleteModal(false);
    }
  }, [selected, deleteApplicant]);

  if (isLoading) {
    return (
      <div className="space-y-6">
        <div className="h-10" />
        <SkeletonTable rows={8} cols={6} />
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Delete Confirmation Modal */}
      <ConfirmModal
        isOpen={showDeleteModal}
        title="Delete Selected Applicants"
        message={`Are you sure you want to delete ${selected.size} selected applicant(s)? This action cannot be undone. All associated applications, documents, and notes will also be permanently removed.`}
        confirmLabel={isDeleting ? "Deleting..." : "Delete All"}
        variant="danger"
        isLoading={isDeleting}
        onConfirm={handleBulkDelete}
        onCancel={() => setShowDeleteModal(false)}
      />

      {/* Header */}
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Applicants</h1>
          <p className="text-muted-foreground text-sm mt-0.5">
            Manage applicant profiles and track visa processing.
          </p>
        </div>
        <Link
          href="/applicants/new"
          className="flex items-center gap-2 bg-primary text-primary-foreground hover:bg-primary/90 px-4 py-2 rounded-lg font-medium text-sm transition-colors shadow-sm"
        >
          <PlusCircle className="w-4 h-4" />
          Add Applicant
        </Link>
      </div>

      {/* Search & Filter Bar */}
      <div className="flex items-center gap-3 flex-wrap">
        <div className="relative flex-1 min-w-[200px] max-w-md">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
          <input
            value={search}
            onChange={(e) => { setSearch(e.target.value); setPage(1); }}
            placeholder="Search name, case #, passport, phone..."
            className="w-full pl-10 pr-4 py-2 rounded-lg bg-background border border-input text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring transition-colors"
          />
        </div>
        <button
          onClick={() => setShowFilters(!showFilters)}
