        <div className="mt-8 pt-6 border-t border-border animate-in fade-in slide-in-from-top-2 duration-300">

          {selectedCountry === "JAPAN" && (
            <div className="bg-red-500/5 p-6 rounded-xl border border-red-500/20">
              <h3 className="font-semibold text-red-600 dark:text-red-400 mb-4 flex items-center gap-2">
                <span className="text-xl">≡ƒç»≡ƒç╡</span> Japan Specific Requirements
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                <div className="space-y-2">
                  <label className="block text-sm font-medium">JLPT / NAT Level</label>
                  <select 
                    {...register("countrySpecificData.jlptLevel")} 
                    className="w-full border border-input bg-background p-2.5 rounded-lg focus:ring-2 focus:ring-red-500/20 outline-none transition-all"
                  >
                    <option value="">Select Level...</option>
                    <option value="N4">N4 (Required for SSW)</option>
                    <option value="N3">N3</option>
                    <option value="N2">N2</option>
                    <option value="NONE">Not Required</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="block text-sm font-medium">COE Application Date</label>
                  <input 
                    type="date" 
                    {...register("countrySpecificData.coeApplicationDate")} 
                    className="w-full border border-input bg-background p-2.5 rounded-lg focus:ring-2 focus:ring-red-500/20 outline-none transition-all scheme-light dark:scheme-dark" 
                  />
                </div>
              </div>
            </div>
          )}

          {selectedCountry === "UAE" && (
            <div className="bg-emerald-500/5 p-6 rounded-xl border border-emerald-500/20">
              <h3 className="font-semibold text-emerald-600 dark:text-emerald-400 mb-4 flex items-center gap-2">
                <span className="text-xl">≡ƒçª≡ƒç¬</span> UAE Specific Requirements
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                <div className="space-y-2">
                  <label className="block text-sm font-medium">MOHRE Skill Level</label>
                  <select 
                    {...register("countrySpecificData.mohreSkillLevel")} 
                    className="w-full border border-input bg-background p-2.5 rounded-lg focus:ring-2 focus:ring-emerald-500/20 outline-none transition-all"
                  >
                    <option value="">Select Skill Level...</option>
                    <option value="1">Level 1 (Degree)</option>
                    <option value="2">Level 2 (Diploma)</option>
                    <option value="3">Level 3 (Skilled)</option>
                    <option value="4">Level 4 (Unskilled)</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="block text-sm font-medium">MOHRE Permit/Offer Number</label>
                  <input 
                    type="text" 
                    {...register("countrySpecificData.mohrePermitNumber")} 
                    className="w-full border border-input bg-background p-2.5 rounded-lg focus:ring-2 focus:ring-emerald-500/20 outline-none transition-all" 
                    placeholder="e.g. 100239482"
                  />
                </div>
              </div>
            </div>
          )}

          {/* Add more countries here (QATAR ID, ImmiAccount for AUS, etc) as needed */}
        </div>
      )}

      {/* Form Action */}
      <div className="pt-4 flex justify-end">
        <button 
          type="submit" 
          disabled={isSubmitting} 
          className="bg-primary text-primary-foreground px-8 py-2.5 rounded-lg font-semibold hover:bg-primary/90 active:scale-95 transition-all flex items-center gap-2 shadow-sm"
        >
          {isSubmitting ? (
            <><Loader2 className="w-5 h-5 animate-spin" /> Processing...</>
          ) : (
            "Create Application"
          )}
        </button>
      </div>
    </form>
  );
}

"use client";

import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { useCreateBranchMutation } from "@/store/api/branchApi";
import { 
  Network, 
  MapPin, 
  Loader2, 
  PlusCircle, 
  X,
  ChevronDown
} from "lucide-react";
import { toast } from "react-hot-toast";

const NEPAL_CITIES = [
  "Kathmandu", "Lalitpur", "Bhaktapur", 
  "Pokhara", "Chitwan", "Biratnagar", 
  "Butwal", "Dharan", "Nepalgunj", 
  "Hetauda", "Janakpur", "Dhangadhi", 
  "Birtamod", "Ilam", "Bharatpur", "Damauli"
].sort();

const branchSchema = z.object({
  name: z.string().min(2, "Branch name must be at least 2 characters"),
  location: z.string().optional(),
});

type BranchFormValues = z.infer<typeof branchSchema>;

interface CreateBranchFormProps {
  companyId: string;
  companyName: string;
  onSuccess?: () => void;
  onCancel?: () => void;
}

export default function CreateBranchForm({ companyId, companyName, onSuccess, onCancel }: CreateBranchFormProps) {
  const [createBranch, { isLoading }] = useCreateBranchMutation();

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<BranchFormValues>({
    resolver: zodResolver(branchSchema),
  });

  const onSubmit = async (data: BranchFormValues) => {
    try {
      const result = await createBranch({
        ...data,
        companyId // System Admin override
      }).unwrap();

      if (result.success) {
        toast.success(`Branch "${data.name}" created for ${companyName}`);
        if (onSuccess) onSuccess();
      }
    } catch (err: any) {
      toast.error(err.data?.error || "Failed to create branch");
    }
  };

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between gap-4 mb-2">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center text-primary">
            <Network className="w-5 h-5" />
          </div>
          <div>
            <h2 className="text-lg font-bold">Add New Branch</h2>
            <p className="text-xs text-muted-foreground uppercase tracking-wider font-semibold">
              For: <span className="text-foreground">{companyName}</span>
            </p>
          </div>
        </div>
        {onCancel && (
          <button 
            onClick={onCancel}
            className="p-2 hover:bg-muted rounded-full transition-colors"
          >
            <X className="w-4 h-4" />
          </button>
        )}
      </div>

      <form onSubmit={handleSubmit(onSubmit)} className="space-y-4 pt-4">
        <div className="space-y-1">
          <label className="text-xs font-medium ml-1 text-muted-foreground">Branch Name</label>
          <div className="relative">
            <PlusCircle className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
            <input 
              {...register("name")}
              className="form-input-premium pl-10"
              placeholder="e.g. Butwal Branch, Damak Center..."
              autoFocus
            />
          </div>
          {errors.name && <p className="text-[10px] text-destructive ml-1">{errors.name.message}</p>}
        </div>

        <div className="space-y-1">
          <label className="text-xs font-medium ml-1 text-muted-foreground">Location (City)</label>
          <div className="relative">
            <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground z-10" />
            <select 
              {...register("location")}
              className="form-input-premium pl-10 appearance-none bg-background cursor-pointer"
            >
              <option value="">Select a City (Optional)</option>
              {NEPAL_CITIES.map(city => (
                <option key={city} value={city}>{city}</option>
              ))}
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground pointer-events-none" />
          </div>
        </div>

        <div className="flex justify-end gap-3 pt-4">
          {onCancel && (
            <button 
              type="button" 
              onClick={onCancel}
              className="px-4 py-2 rounded-xl text-sm font-medium hover:bg-muted transition-colors disabled:opacity-50"
              disabled={isLoading}
            >
              Cancel
            </button>
          )}
          <button 
            type="submit" 
            className="premium-button flex items-center gap-2 py-2 px-6 disabled:opacity-50"
            disabled={isLoading}
          >
            {isLoading ? (
              <>
                <Loader2 className="w-4 h-4 animate-spin" />
                Creating...
              </>
            ) : (
              <>
                <Network className="w-4 h-4" />
                Create Branch
              </>
            )}
          </button>
        </div>
      </form>
    </div>
  );
}

"use client";

import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { useProvisionCompanyMutation } from "@/store/api/companyApi";
import { 
  Building2, 
  Mail, 
  Phone, 
  User, 
  FileText, 
  Loader2, 
  CheckCircle2,
  Copy,
  ExternalLink
} from "lucide-react";
import { toast } from "react-hot-toast";
import { useState } from "react";

const registerSchema = z.object({
  businessName: z.string().min(2, "Business name is required"),
  registrationNumber: z.string().optional(),
  contactEmail: z.string().email("Invalid contact email"),
  contactPhone: z.string().optional(),
  adminName: z.string().min(2, "Admin name is required"),
  adminEmail: z.string().email("Invalid admin email"),
});

type RegisterFormValues = z.infer<typeof registerSchema>;

interface RegisterCompanyFormProps {
  onSuccess?: () => void;
  onCancel?: () => void;
}

export default function RegisterCompanyForm({ onSuccess, onCancel }: RegisterCompanyFormProps) {
  const [provisionCompany, { isLoading }] = useProvisionCompanyMutation();
  const [provisionedData, setProvisionedData] = useState<{ inviteLink: string } | null>(null);

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<RegisterFormValues>({
    resolver: zodResolver(registerSchema),
  });

  const onSubmit = async (data: RegisterFormValues) => {
    try {
      const result = await provisionCompany(data).unwrap();
      if (result.success) {
        toast.success("Agency provisioned successfully!");
        setProvisionedData({ inviteLink: result.data.inviteLink });
        if (onSuccess) {
          // We wait for the user to copy the link before closing, 
          // or handle it in the success state UI below.
        }
      }
    } catch (err: any) {
      toast.error(err.data?.error || "Failed to provision agency");
    }
  };

  const copyLink = () => {
    if (provisionedData?.inviteLink) {
      navigator.clipboard.writeText(provisionedData.inviteLink);
      toast.success("Invitation link copied to clipboard!");
    }
  };

  if (provisionedData) {
    return (
      <div className="p-8 text-center space-y-6 animate-in zoom-in-95 duration-300">
        <div className="w-20 h-20 bg-emerald-500/10 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-4">
          <CheckCircle2 className="w-10 h-10" />
        </div>
        <div>
          <h2 className="text-2xl font-bold text-foreground">Agency Provisioned!</h2>
          <p className="text-muted-foreground mt-2 max-w-sm mx-auto">
            The company has been created. Please share this secure activation link with the primary administrator.
          </p>
        </div>

        <div className="bg-muted/50 border border-border p-4 rounded-xl flex items-center gap-3 group">
          <div className="truncate text-xs font-mono text-muted-foreground flex-1 text-left">
            {provisionedData.inviteLink}
          </div>
          <button 
            onClick={copyLink}
            className="p-2 hover:bg-background rounded-lg transition-colors text-primary group-hover:scale-110"
            title="Copy Link"
          >
            <Copy className="w-4 h-4" />
          </button>
        </div>

        <div className="flex flex-col gap-3 pt-4">
          <button 
            onClick={() => window.open(provisionedData.inviteLink, '_blank')}
            className="premium-button flex items-center justify-center gap-2"
          >
            <ExternalLink className="w-4 h-4" />
            Open Activation Page
          </button>
          <button 
            onClick={onCancel}
            className="text-sm text-muted-foreground hover:text-foreground transition-colors"
          >
            Close Provisioning Wizard
          </button>
        </div>
