"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { signOut } from "next-auth/react";
import Sidebar from "@/components/layout/Sidebar";
import TopBar from "@/components/layout/TopBar";
import CommandPalette from "@/components/layout/CommandPalette";
import ConfirmModal from "@/components/ui/ConfirmModal";
import { ToastProvider } from "@/components/ui/Toast";
import { useKeyboardShortcuts } from "@/hooks/useKeyboardShortcuts";

interface DashboardShellProps {
  children: React.ReactNode;
  role: string;
  userName: string;
}

export default function DashboardShell({
  children,
  role,
  userName,
}: DashboardShellProps) {
  const router = useRouter();
  const [searchOpen, setSearchOpen] = useState(false);
  const [signOutConfirm, setSignOutConfirm] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  useKeyboardShortcuts({
    onNewApplicant: () => router.push("/applicants/new"),
    onSearch: () => setSearchOpen(true),
    onEscape: () => {
      setSearchOpen(false);
      setSignOutConfirm(false);
      setMobileMenuOpen(false);
    },
  });

  useEffect(() => {
    if (mobileMenuOpen) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "";
    }
    return () => {
      document.body.style.overflow = "";
    };
  }, [mobileMenuOpen]);

  const handleSignOut = () => {
    setSignOutConfirm(true);
  };

  const confirmSignOut = async () => {
    await signOut({ callbackUrl: "/login" });
  };

  return (
    <div className="min-h-screen bg-background text-foreground flex">
      {/* Desktop Sidebar */}
      <Sidebar
        role={role}
        userName={userName}
        onSignOut={handleSignOut}
      />

      {/* Mobile Sidebar Overlay */}
      {mobileMenuOpen && (
        <div className="md:hidden fixed inset-0 z-50 flex">
          <div
            className="absolute inset-0 bg-black/50"
            onClick={() => setMobileMenuOpen(false)}
          />
          <div className="relative w-64 bg-sidebar border-r border-sidebar-border">
            <Sidebar
              role={role}
              userName={userName}
              onSignOut={handleSignOut}
            />
          </div>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0">
        <TopBar
          onSearchOpen={() => setSearchOpen(true)}
          onMobileMenuToggle={() => setMobileMenuOpen(!mobileMenuOpen)}
          userName={userName}
          onSignOut={handleSignOut}
        />

        {/* Page Content */}
        <div className="flex-1 overflow-auto p-4 md:p-6 lg:p-8">
          {children}
        </div>
      </main>

      {/* Command Palette */}
      <CommandPalette
        isOpen={searchOpen}
        onClose={() => setSearchOpen(false)}
      />

      {/* Sign Out Confirmation */}
      <ConfirmModal
        isOpen={signOutConfirm}
        title="Sign Out"
        message="Are you sure you want to sign out? You will need to log in again to access the dashboard."
        confirmLabel="Sign Out"
        cancelLabel="Cancel"
        variant="warning"
        onConfirm={confirmSignOut}
        onCancel={() => setSignOutConfirm(false)}
      />
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import {
  LayoutDashboard,
  Users,
  UserPlus,
  ClipboardList,
  FileText,
  Kanban,
  Globe,
  BarChart3,
  Download,
  History,
  Settings,
  Building2,
  Bell,
  ChevronDown,
  ChevronLeft,
  ChevronRight,
  LogOut,
  PanelLeftClose,
  PanelLeftOpen,
} from "lucide-react";

interface SidebarProps {
  role: string;
  userName: string;
  onSignOut: () => void;
}

interface NavItem {
  name: string;
  href: string;
  icon: React.ElementType;
}

interface NavGroup {
  title: string;
  items: NavItem[];
  adminOnly?: boolean;
  onlySystemAdmin?: boolean;
}

const NAV_GROUPS: NavGroup[] = [
  {
    title: "Overview",
    items: [
      { name: "Dashboard", href: "/dashboard/staff", icon: LayoutDashboard },
    ],
  },
  {
    title: "Applicants",
    items: [
      { name: "All Applicants", href: "/applicants", icon: Users },
      { name: "Add New", href: "/applicants/new", icon: UserPlus },
      { name: "Document Checklist", href: "/applicants/documents", icon: ClipboardList },
    ],
  },
  {
    title: "Applications",
    items: [
      { name: "Active Applications", href: "/applications", icon: FileText },
      { name: "Pipeline Tracker", href: "/applications/board", icon: Kanban },
      { name: "By Country", href: "/applications/by-country", icon: Globe },
    ],
  },
  {
    title: "Reports",
    adminOnly: true,
    items: [
      { name: "Analytics", href: "/dashboard/admin/reports", icon: BarChart3 },
      { name: "Export Data", href: "/dashboard/admin/reports/export", icon: Download },
      { name: "Audit Log", href: "/dashboard/admin/reports/audit", icon: History },
    ],
  },
  {
    title: "Settings",
    adminOnly: true,
    items: [
      { name: "User Management", href: "/dashboard/admin/settings/users", icon: Users },
      { name: "Agency Profile", href: "/dashboard/admin/settings/agency", icon: Building2 },
      { name: "Notifications", href: "/dashboard/admin/settings/notifications", icon: Bell },
    ],
  },
  {
    title: "Administration",
    onlySystemAdmin: true,
    items: [
      { name: "Agencies", href: "/dashboard/admin/companies", icon: Building2 },
    ],
  },
];

function getInitials(name: string) {
  return name
    .split(" ")
    .map((w) => w[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);
}

export default function Sidebar({ role, userName, onSignOut }: SidebarProps) {
  const pathname = usePathname();
  const [collapsed, setCollapsed] = useState(false);
  const [expandedGroups, setExpandedGroups] = useState<Record<string, boolean>>(() => {
    // Default all groups expanded
    const map: Record<string, boolean> = {};
    NAV_GROUPS.forEach((g) => (map[g.title] = true));
    return map;
  });

  // Auto-collapse below 1280px
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 1280) {
        setCollapsed(true);
      }
    };
    handleResize();
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const toggleGroup = (title: string) => {
    if (collapsed) return;
    setExpandedGroups((prev) => ({ ...prev, [title]: !prev[title] }));
  };

  const isAdmin = role === "SYSTEM_ADMIN" || role === "COMPANY_ADMIN" || role === "ADMIN";
  const isSystemAdmin = role === "SYSTEM_ADMIN";

  const filteredGroups = NAV_GROUPS.filter(
    (group) => {
      if (group.onlySystemAdmin && !isSystemAdmin) return false;
      if (group.adminOnly && !isAdmin) return false;
      return true;
    }
  );

  // Update the dashboard link for admin
  const processedGroups = filteredGroups.map((group) => {
    if (group.title === "Overview" && isAdmin) {
      return {
        ...group,
        items: [
          { name: "Dashboard", href: "/dashboard/admin", icon: LayoutDashboard },
        ],
      };
    }
    return group;
  });

  return (
    <aside
      className={`hidden md:flex flex-col bg-sidebar text-sidebar-foreground border-r border-sidebar-border transition-all duration-300 ${
        collapsed ? "w-[68px]" : "w-64"
      }`}
    >
      {/* Logo */}
      <div className="h-16 flex items-center px-4 border-b border-sidebar-border shrink-0">
        <div className="w-8 h-8 rounded-lg bg-primary flex items-center justify-center shrink-0">
          <span className="text-primary-foreground font-bold text-sm">H</span>
        </div>
        {!collapsed && (
          <span className="ml-3 font-bold text-lg text-sidebar-primary truncate">
            HamroClient
          </span>
        )}
      </div>

      {/* Nav Groups */}
      <nav className="flex-1 overflow-y-auto py-3 px-2 space-y-1">
        {processedGroups.map((group) => (
          <div key={group.title} className="mb-1">
            {/* Group Header */}
            {!collapsed && (
              <button
                onClick={() => toggleGroup(group.title)}
                className="flex items-center justify-between w-full px-3 py-1.5 text-[11px] font-semibold uppercase text-muted-foreground/70 hover:text-muted-foreground transition-colors"
              >
                {group.title}
                <ChevronDown
                  className={`w-3 h-3 transition-transform ${
                    expandedGroups[group.title] ? "" : "-rotate-90"
                  }`}
                />
              </button>
            )}

            {/* Group Items */}
            {(collapsed || expandedGroups[group.title]) && (
              <div className={collapsed ? "space-y-1 mt-1" : "space-y-0.5"}>
                {group.items.map((item) => {
                  const Icon = item.icon;
                  const isActive =
                    pathname === item.href ||
                    (item.href !== "/" && pathname.startsWith(item.href + "/"));

                  return (
                    <Link
                      key={item.href}
                      href={item.href}
                      title={collapsed ? item.name : undefined}
                      className={`flex items-center gap-3 rounded-lg transition-colors ${
                        collapsed
                          ? "justify-center px-2 py-2.5"
                          : "px-3 py-2"
                      } ${
                        isActive
                          ? "bg-sidebar-accent text-sidebar-accent-foreground font-medium"
                          : "text-sidebar-foreground/70 hover:bg-sidebar-accent/50 hover:text-sidebar-foreground"
                      }`}
                    >
                      <Icon className={`shrink-0 ${collapsed ? "w-5 h-5" : "w-4 h-4"}`} />
                      {!collapsed && (
                        <span className="text-sm truncate">{item.name}</span>
                      )}
                    </Link>
                  );
                })}
              </div>
            )}
          </div>
        ))}
      </nav>

      {/* Bottom: User & Collapse Toggle */}
      <div className="border-t border-sidebar-border p-2 space-y-2 shrink-0">
        {/* User Info */}
        <div
          className={`flex items-center gap-3 rounded-lg bg-muted/30 ${
            collapsed ? "justify-center p-2" : "px-3 py-2.5"
          }`}
        >
          <div className="w-8 h-8 rounded-full bg-primary/20 text-primary flex items-center justify-center text-xs font-bold shrink-0">
            {getInitials(userName)}
          </div>
          {!collapsed && (
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium truncate text-sidebar-foreground">
                {userName}
              </p>
              <span className="text-[10px] font-semibold uppercase px-1.5 py-0.5 rounded bg-primary/10 text-primary">
                {role}
              </span>
            </div>
          )}
        </div>

        {/* Sign Out */}
        <button
          onClick={onSignOut}
          title={collapsed ? "Sign Out" : undefined}
          className={`flex items-center gap-3 w-full rounded-lg text-muted-foreground hover:bg-destructive/10 hover:text-destructive transition-colors ${
            collapsed ? "justify-center p-2" : "px-3 py-2"
          }`}
        >
          <LogOut className="w-4 h-4 shrink-0" />
          {!collapsed && <span className="text-sm">Sign Out</span>}
        </button>

        {/* Collapse Toggle */}
        <button
          onClick={() => setCollapsed(!collapsed)}
          className={`flex items-center gap-3 w-full rounded-lg text-muted-foreground hover:bg-muted hover:text-foreground transition-colors ${
            collapsed ? "justify-center p-2" : "px-3 py-2"
          }`}
          title={collapsed ? "Expand sidebar" : "Collapse sidebar"}
        >
          {collapsed ? (
            <PanelLeftOpen className="w-4 h-4" />
          ) : (
            <>
              <PanelLeftClose className="w-4 h-4" />
              <span className="text-sm">Collapse</span>
            </>
          )}
        </button>
      </div>
    </aside>
  );
}

"use client";

import { useState } from "react";
import type { ApplicantDocument } from "@/store/api/applicantDetailApi";
import {
  useGetSecureDocumentUrlQuery,
  useUpdateDocumentStatusMutation,
  useDeleteDocumentMutation,
} from "@/store/api/applicantDetailApi";
import {
  X,
  ShieldCheck,
  Ban,
  UploadCloud,
  Loader2,
  Trash2,
  CheckCircle2,
  AlertTriangle,
  DownloadCloud,
} from "lucide-react";

interface DocumentReviewModalProps {
  document: ApplicantDocument;
  applicantId: string;
  onClose: () => void;
}

export default function DocumentReviewModal({
  document,
  applicantId,
  onClose,
}: DocumentReviewModalProps) {
  const { data, isLoading, isError } = useGetSecureDocumentUrlQuery(document.id);
  const [updateStatus, { isLoading: isUpdating }] = useUpdateDocumentStatusMutation();
  const [deleteDocument, { isLoading: isDeleting }] = useDeleteDocumentMutation();

  const [expiryDate, setExpiryDate] = useState(
    document.expiryDate ? new Date(document.expiryDate).toISOString().split("T")[0] : ""
  );
  const [isAttested, setIsAttested] = useState(document.isAttested);

  const handleUpdate = async (status: boolean | null) => {
    try {
      const payload: Partial<ApplicantDocument> = {
        isAttested,
      };

      if (expiryDate) {
        payload.expiryDate = new Date(expiryDate).toISOString();
      }

      if (status !== null) {
        payload.isVerified = status;
      }

      await updateStatus({
        id: document.id,
        applicantId,
        data: payload,
      }).unwrap();

    } catch (err) {
      console.error("Failed to update document status:", err);
    }
  };

  const handleDelete = async () => {
    if (!confirm("Are you sure you want to permanently delete this document? This removes the file from secure storage and cannot be undone.")) return;
    try {
      await deleteDocument({ docId: document.id, applicantId }).unwrap();
      onClose();
    } catch (err) {
      console.error("Failed to delete document:", err);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />

      <div className="relative w-full max-w-5xl h-[85vh] bg-card border border-border shadow-2xl rounded-2xl flex flex-col md:flex-row overflow-hidden animate-in fade-in zoom-in-95 duration-200">

        {/* ΓöÇΓöÇ Left Column: Document Viewer ΓöÇΓöÇ */}
        <div className="flex-1 bg-muted/30 border-b md:border-b-0 md:border-r border-border flex flex-col relative">
          <div className="absolute top-4 left-4 z-10">
             <span className="bg-background/80 backdrop-blur border border-border px-3 py-1.5 rounded-lg text-xs font-semibold shadow-sm">
               {document.title}
             </span>
          </div>

          <div className="flex-1 flex items-center justify-center p-4 overflow-hidden">
            {isLoading ? (
              <div className="flex flex-col items-center text-muted-foreground gap-3">
                <Loader2 className="w-8 h-8 animate-spin" />
                <p className="text-sm font-medium">Generating secure viewing link...</p>
              </div>
            ) : isError || !data?.success ? (
              <div className="flex flex-col items-center text-destructive gap-3 text-center px-4">
                <AlertTriangle className="w-8 h-8" />
                <p className="text-sm font-medium">Failed to load secure document.</p>
                <p className="text-xs opacity-80">The file might have been moved or the signature expired.</p>
              </div>
            ) : data.mimeType === "application/pdf" ? (
              <div className="w-full h-full flex flex-col relative">
                <iframe
                  src={`${data.signedUrl}#view=FitH`}
                  title={document.title}
                  className="w-full h-full rounded-xl border border-border/50 shadow-inner"
                />
                {/* Fallback link always visible or below in case of issues */}
                <div className="mt-4 flex justify-center">
                  <a 
                    href={data.signedUrl} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="inline-flex items-center gap-2 px-4 py-2 bg-muted text-muted-foreground hover:text-foreground rounded-lg text-xs font-medium border border-border transition-colors"
                  >
                    <DownloadCloud className="w-4 h-4" /> Open PDF in new tab
                  </a>
                </div>
              </div>
            ) : (
              <img 
                src={data.signedUrl} 
                alt={document.title}
                className="max-w-full max-h-full object-contain rounded-xl shadow-inner border border-border/50"
              />
            )}
          </div>
        </div>

        {/* ΓöÇΓöÇ Right Column: Metadata & Controls ΓöÇΓöÇ */}
        <div className="w-full md:w-[400px] flex flex-col bg-card shrink-0">
          <div className="p-5 border-b border-border flex items-center justify-between">
            <h2 className="text-lg font-semibold text-foreground">Review Document</h2>
            <button
              onClick={onClose}
              className="p-1.5 rounded-lg text-muted-foreground hover:bg-muted transition-colors"
            >
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-5 space-y-6">

            {/* Meta Info */}
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-wider font-bold mb-1">Details</p>
              <table className="w-full text-sm">
                <tbody>
                  <tr>
                    <td className="py-1 text-muted-foreground">Category</td>
                    <td className="py-1 font-medium">{document.category}</td>
                  </tr>
                  <tr>
                    <td className="py-1 text-muted-foreground">Uploaded</td>
                    <td className="py-1 font-medium">{new Date(document.uploadedAt).toLocaleDateString()}</td>
                  </tr>
                  {document.countrySpecific && document.countrySpecific !== "ALL" && (
                    <tr>
                      <td className="py-1 text-muted-foreground">Country</td>
                      <td className="py-1 font-medium">{document.countrySpecific}</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>

            {/* Verification Status Controls */}
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-wider font-bold mb-3">Verification</p>

              <div className="grid grid-cols-2 gap-2">
                <button
                  onClick={() => handleUpdate(true)}
                  disabled={isUpdating}
                  className={`flex flex-col items-center justify-center gap-2 p-3 rounded-xl border-2 transition-all ${
                    document.isVerified 
                      ? "border-emerald-500 bg-emerald-50/50 text-emerald-700 dark:bg-emerald-950/30" 
                      : "border-transparent bg-muted/50 text-muted-foreground hover:bg-muted"
                  }`}
                >
                  <ShieldCheck className="w-5 h-5" />
                  <span className="text-xs font-semibold">Verified</span>
                </button>

                <button
                  onClick={() => handleUpdate(false)}
                  disabled={isUpdating}
                  className={`flex flex-col items-center justify-center gap-2 p-3 rounded-xl border-2 transition-all ${
                    !document.isVerified 
                      ? "border-amber-500 bg-amber-50/50 text-amber-700 dark:bg-amber-950/30" 
                      : "border-transparent bg-muted/50 text-muted-foreground hover:bg-muted"
                  }`}
                >
                  <Ban className="w-5 h-5" />
                  <span className="text-xs font-semibold">Rejected / Reset</span>
                </button>
              </div>
            </div>

            {/* Additional Metadata Updates */}
            <div className="space-y-4 pt-4 border-t border-border">
              <div>
                <label className="flex items-center gap-3 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={isAttested}
                    onChange={(e) => setIsAttested(e.target.checked)}
                    className="w-4 h-4 rounded text-primary border-border focus:ring-primary/30"
                  />
                  <span className="text-sm font-medium text-foreground">
                    Document is officially attested (MOFA/Embassy)
                  </span>
                </label>
              </div>

              <div>
                <label className="text-xs font-medium text-muted-foreground mb-1 block">Expiry Date (Optional)</label>
                <input
                  type="date"
                  value={expiryDate}
                  onChange={(e) => setExpiryDate(e.target.value)}
                  className="w-full text-sm bg-background border border-border rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-primary/30"
                />
              </div>

              <div className="flex justify-end pt-2">
                <button
                  onClick={() => handleUpdate(null)}
                  disabled={isUpdating || (isAttested === document.isAttested && expiryDate === (document.expiryDate ? new Date(document.expiryDate).toISOString().split('T')[0] : ""))}
                  className="inline-flex items-center gap-1.5 px-4 py-2 text-xs font-semibold bg-secondary text-secondary-foreground rounded-lg hover:bg-secondary/80 disabled:opacity-50 transition-colors"
                >
                  {isUpdating ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <CheckCircle2 className="w-3.5 h-3.5" />}
                  Save Metadata
                </button>
              </div>
            </div>

          </div>

          {/* Danger Zone */}
          <div className="p-5 border-t border-border bg-destructive/5">
            <button
               onClick={handleDelete}
               disabled={isDeleting}
               className="w-full inline-flex items-center justify-center gap-2 px-4 py-2 text-xs font-semibold text-destructive border border-destructive/20 hover:bg-destructive hover:text-destructive-foreground rounded-lg transition-colors"
            >
              {isDeleting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Trash2 className="w-4 h-4" />}
              Permanently Delete File
            </button>
          </div>

        </div>
      </div>
    </div>
  );
}

