"use client";

import { useState, useEffect, useRef } from "react";
import { type LucideIcon, TrendingUp, TrendingDown } from "lucide-react";

export function useCountUp(target: number, duration = 1200) {
  const [count, setCount] = useState(0);
  const frameRef = useRef<number>(0);

  useEffect(() => {
    let start = 0;
    const startTime = Date.now();

    const tick = () => {
      const elapsed = Date.now() - startTime;
      const progress = Math.min(elapsed / duration, 1);
      // Ease out cubic
      const eased = 1 - Math.pow(1 - progress, 3);
      setCount(Math.round(eased * target));

      if (progress < 1) {
        frameRef.current = requestAnimationFrame(tick);
      }
    };

    frameRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(frameRef.current);
  }, [target, duration]);

  return count;
}

interface KPICardProps {
  label?: string; // Admin style
  title?: string; // Staff style
  value: number;
  change?: number; // Admin style (percentage)
  trend?: string; // Staff style (text string)
  icon: LucideIcon;
  suffix?: string;
  delay?: number;
  color?: "primary" | "accent" | "destructive" | "muted" | "success" | "warning";
}

const colorMap = {
  primary: "bg-primary/10 text-primary border-primary/20",
  accent: "bg-accent/10 text-accent-foreground border-accent/20",
  destructive: "bg-destructive/10 text-destructive border-destructive/20",
  muted: "bg-muted text-muted-foreground border-border",
  success: "bg-success/10 text-success border-success/20",
  warning: "bg-warning/10 text-warning-foreground border-warning/20",
};

export default function KPICard({
  label,
  title,
  value,
  change,
  trend,
  icon: Icon,
  suffix = "",
  delay = 0,
  color = "primary",
}: KPICardProps) {
  const animatedValue = useCountUp(value);

  // Decide between Admin dashboard change (percentage) or Staff dashboard trend (text)
  const isPositive = (change !== undefined && change >= 0) || color === "success" || color === "primary";

  return (
    <div
      className="bg-card border border-border rounded-xl p-5 shadow-sm hover:shadow-md transition-shadow"
      style={delay > 0 ? { animation: `countUp 0.5s ease-out ${delay}ms both` } : undefined}
    >
      <div className="flex items-start justify-between">
        <div className="space-y-1 w-full relative">
          {/* Top Label/Title & Trend Area for Admin View vs Staff View */}
          {change !== undefined ? (
            // Admin View Layout
            <>
              <div className="flex items-start justify-between w-full mb-3">
                <div className={`p-2.5 rounded-lg border ${colorMap[color]}`}>
                  <Icon className="w-5 h-5" />
                </div>
                <div
                  className={`flex items-center gap-0.5 text-xs font-semibold ${
                    isPositive ? "text-emerald-600" : "text-red-500"
                  }`}
                >
                  {isPositive ? <TrendingUp className="w-3.5 h-3.5" /> : <TrendingDown className="w-3.5 h-3.5" />}
                  {Math.abs(change)}%
                </div>
              </div>
              <p className="text-2xl font-bold text-foreground tracking-tight">
                {animatedValue}{suffix}
              </p>
              <p className="text-xs text-muted-foreground mt-1">{label}</p>
            </>
          ) : (
            // Staff View Layout
            <div className="flex items-start justify-between w-full">
              <div className="space-y-2">
                <p className="text-sm font-medium text-muted-foreground">{title || label}</p>
                <p className="text-3xl font-bold tracking-tight text-foreground">
                  {animatedValue}{suffix}
                </p>
                {trend && (
                  <p className="text-xs text-muted-foreground">{trend}</p>
                )}
              </div>
              <div className={`p-3 rounded-lg border shrink-0 ${colorMap[color]}`}>
                <Icon className="w-5 h-5" />
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { NextAuthOptions } from "next-auth";
import CredentialsProvider from "next-auth/providers/credentials";

export const authOptions: NextAuthOptions = {
  session: {
    strategy: "jwt",
  },
  pages: {
    signIn: "/login",
  },
  providers: [
    CredentialsProvider({
      name: "Credentials",
      credentials: {
        email: { label: "Email", type: "email", placeholder: "admin@example.com" },
        password: { label: "Password", type: "password" },
      },
      async authorize(credentials) {
        if (!credentials?.email || !credentials.password) {
          return null;
        }

        try {
          const baseUrl = process.env.NEXT_PUBLIC_API_URL || "http://localhost:3001/api";
          const res = await fetch(`${baseUrl}/auth/verify`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              email: credentials.email,
              password: credentials.password,
            }),
          });

          if (res.ok) {
            const user = await res.json();
            return user;
          }
          return null;
        } catch (error) {
          console.error("Frontend Auth Error:", error);
          return null;
        }
      },
    }),
  ],
  callbacks: {
    async jwt({ token, user, trigger, session }) {
      if (user) {
        token.id = user.id;
        token.role = user.role;
        token.companyId = (user as any).companyId;
        token.branchId = user.branchId;
        token.isProfileComplete = user.isProfileComplete;
      }

      if (trigger === "update" && session) {
        // Update the token with session data
        if (session.isProfileComplete !== undefined) {
          token.isProfileComplete = session.isProfileComplete;
        }
      }

      return token;
    },
    async session({ session, token }) {
      if (token && session.user) {
        session.user.id = token.id as string;
        session.user.role = token.role as "SYSTEM_ADMIN" | "COMPANY_ADMIN" | "BRANCH_MANAGER" | "AGENT";
        session.user.companyId = token.companyId as string | null;
        session.user.branchId = token.branchId as string | null;
        session.user.isProfileComplete = token.isProfileComplete as boolean;
      }
      return session;
    },
  },
};

